/**
 * @param {string} titleCaption
 * @param {string} question
 * @param {string} cancelButtonCaption
 * @param {string} proceedButtonCaption
 * @returns {Promise.<boolean>}
 */
export async function ShowCustomConfirmation(titleCaption, question, cancelButtonCaption, proceedButtonCaption) {
	// BEGIN USER CODE
    if (!question) {
        return Promise.reject(new Error("Input parameter 'Question' is required"));
    }
    const cancel = cancelButtonCaption || "Cancel";
    const proceed = proceedButtonCaption || "OK";
    // Native platform
    if (navigator && navigator.product === "ReactNative") {
        const Alert = require("react-native").Alert;
        return new Promise(resolve => {
            Alert.alert(titleCaption, question, [
                { text: cancel, onPress: () => resolve(false), style: "cancel" },
                { text: proceed, onPress: () => resolve(true) }
            ]);
        });
    }
    // Other platforms
    return new Promise(resolve => {
        mx.ui.confirmation({
            content: question,
            proceed,
            cancel,
            handler: () => resolve(true),
            onCancel: () => resolve(false)
        });
        var dialog = document.querySelector('div.modal-dialog.mx-dialog');
        var dialogHeader = document.querySelector('.mx-dialog .mx-dialog-header > .mx-dialog-caption'); 
        if (dialogHeader) {
            dialogHeader.textContent = titleCaption;
        }
        if (dialog) {
            dialog.classList.add('disposition_details_warning');
        }
    });
	// END USER CODE
}
